def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 10):
            factor = (j**0.5) * np.tanh(utilization * j)
            if factor < 0.1:
                score += np.exp(-factor**2) * np.cos(j) + j * 0.1
            elif 0.1 <= factor < 0.3:
                score += np.log1p(factor * j) / (j + 1)
            elif 0.3 <= factor < 0.6:
                score += np.sin(np.pi * factor * j) * np.sqrt(j)
            elif 0.6 <= factor < 1:
                score += (np.arctan(factor * j) + 1) * (j / 2)
            else:
                score += (factor**3) / (j + factor)
            if j % 3 == 0 and score > 15:
                for m in range(j):
                    score -= (m + 1) * np.exp(-factor * m) * 0.02
                score *= 0.95
            elif j % 4 == 0 and score < 5:
                score += np.sqrt(j) * factor
        if item < 0.4:
            if bin_capacity > item * 6:
                score *= 1.25
                for n in range(5):
                    score += np.tanh((n + 1) * utilization) * 0.1
            elif bin_capacity < item * 3:
                score *= 1.15
                score -= np.prod(np.cos(np.linspace(0.2, utilization, 7)))
            else:
                score += np.sum(np.log1p(np.arange(1, 4) * utilization))
        elif 0.4 <= item <= 1.2:
            if bin_capacity < item * 2.8:
                score *= 1.6
            elif bin_capacity > item * 8:
                score *= 0.55
                for p in range(1, 6):
                    score -= np.sin(p * utilization * np.pi) * 0.05 * p
            else:
                for q in range(1, 7):
                    val = np.tanh(q * utilization) * np.cos(q * np.pi / 4)
                    score += val * (q / 3)
        else:
            max_k = max(1, int(bin_capacity // item))
            for k in range(1, max_k + 4):
                increment = np.sin(k * utilization + k / 2) + np.log1p(k + utilization)
                if increment > 1.2:
                    score += increment * 0.8
                else:
                    score += increment ** 1.7
                if k % 3 == 0 and score > 25:
                    score *= 0.9
            if bin_capacity < item * 5:
                score *= 1.5
            elif bin_capacity > item * 12:
                score *= 0.75
            else:
                val = np.sum(np.sqrt(np.arange(1, 5) * utilization)) + np.cosh(utilization)
                score += val
        if score < 0:
            score = abs(score) + 3
        if score > 60:
            score = 60 + np.log(score - 59)
        priorities[i] = score
    return priorities
